  ('ec13c7b9-370d-4353-aea0-0bdfe5a3c5c3', 'MT.1.UM.MC.2', 'Use phrases such as ''holds more than'', ''holds same as'' and ''holds less than'' to compare the capacity of two containers.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('3b60f16d-39ec-4dd3-82f5-849812bbe877', 'MT.1.UM.MM.1', 'Estimate and measure the mass of objects using non-standard units.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e082d018-e662-4bb5-a134-21efade84ea0', 'MT.1.UM.MM.2', 'Estimate and measure the mass of objects using the kilogram as the unit of measure.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('30b8f6d4-025a-4042-933a-5122a43d4bf7', 'MT.1.UM.MM.3', 'Compare the mass of two objects, using phrases (such as ''heavier than'', same mass as'', and ''lighter than'').', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('503fddc3-8122-4337-a7dd-95310e99e417', 'MT.1.UM.MW.1', 'Recognize coins and notes (5-cent, 10-cent, $1, $5, and $10) of the Eastern Caribbean currency; and read and write amounts of money up to $20 in a variety of ways.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Money Works', 'MW', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('64233933-4e61-4065-9ae7-8b43652b1183', 'MT.1.UM.MW.2', 'Represent amounts of money up to $20 using up to three combinations of coins only or combinations of notes only [e.g. (twenty cents as 10c + 10c or as 10c + 5c + 5c); (ten dollars as $5 + $5); (Eleven dollars as $10 + $1 or as $5 + $5 + $1); (twenty dollars as $10 + $10 or as $10 + $5 + $5)]', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Money Works', 'MW', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('44510ad0-faf4-4c8f-9425-8a24051f5006', 'MT.1.UM.MW.3', 'Compare the value of two coins or notes (5c, 10c, $1, $5, $10) using the words ''more than'', ''same value as'' and ''less than''', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Money Works', 'MW', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dc70dc42-ad2b-4b80-9b21-96c26e49c77b', 'MT.1.UM.MW.4', 'Recognize that although there is no 1-cent coin in EC currency, that a 5-cent coin is equivalent to five 1-cent and a 10-cent coin as equivalent to ten 1-cent coins', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Money Works', 'MW', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1e093ba6-695d-471b-a597-dbe59f0c4875', 'MT.1.UM.UT.1', 'Name the days of the week in order and recognize the names.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b7964e7e-eae8-489d-92c7-410cb2804937', 'MT.1.UM.UT.2', 'Name the months of the year and recognize the names.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0ac9b6be-d28d-40de-ba83-0e9b773a73f1', 'MT.1.UM.UT.3', 'State and write the date of the current day.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('bee39304-fc82-409f-a2f5-b35f76441306', 'MT.1.UM.UT.4', 'Use time vocabulary appropriately (e.g., now, later, soon, earlier) relative to year, month, week, day and hour.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('09f7b737-a7b3-44f2-8e1c-7c464a59f109', 'MT.1.UM.UT.5', 'Sequence events in chronological order using expressions such as ''first'', ''next'', ''before'', ''after'', ''tomorrow'', ''yesterday'', ''morning''.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a4cfcac8-2208-4d79-91bd-e0c210530a3b', 'MT.1.UM.UT.6', 'Tell time on the hour on model clocks and templates.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d6c286a6-9978-486d-aaaa-1a74821db6c6', 'MT.1.UM.UT.7', 'Read and write time on the hour in several ways.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1441c5bf-bbc0-4695-816f-3e4c106fd890', 'MT.1.UM.UT.8', 'Represent time on the hour on analog clock templates.', 'mathematics', '1', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('364c3504-c5fe-42e4-8d03-3eb601d2d00d', 'MT.1.NS.NP.1', 'Complete a sequence of numbers that involves counting by 1''s, 2''s, and 5''s, and starting with a multiple of the number by which the count is done; and where the largest number in the sequence is less than or equal to 20.', 'mathematics', '1', 'Number Sense', 'NS', 'Number Patterns', 'NP', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d17dc424-3550-455a-b03a-13f2d5862a68', 'MT.1.NS.NP.2', 'Generate and interpret whole number sequences involving adding and subtracting one and two; and where sequence consists no more than five elements (e.g. 3, 5, 7, 9; 10, 8, 6, 4)', 'mathematics', '1', 'Number Sense', 'NS', 'Number Patterns', 'NP', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('aedc986f-4bbc-4075-8bf1-095762e03f8b', 'MT.1.NS.NP.3', 'Use a variety of tools (such as counters, pictures, number lines and drawings) to generate and interpret whole number patterns [e.g. (5 = 1 + 4; 2 + 3; 3+2; 4+1); (2=2; 4 = 2+2; 6 =2+2+2); (5 = 4 + 1; 6 = 5 + 1; 7 = 6 + 1)]', 'mathematics', '1', 'Number Sense', 'NS', 'Number Patterns', 'NP', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9a824a54-fd7a-463a-af3f-923a45bc73bc', 'MT.1.NS.OS.1', 'Use examples to explain the procedures for carrying out addition, subtraction, and repeated addition, using appropriate vocabulary such as ''total'', ''sum'', ''join together'', ''subtract'', ''take away'', and ''sets of''.', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('180cff06-1c48-46e8-80a8-e871b6784bb5', 'MT.1.NS.OS.2', 'Use several devices (e.g., concrete and pictorial representations, a calculator) to explore the properties of addition (e.g., if 5 + 2 =7 then 2 + 5 = 7).', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7c45ab6d-e386-46de-8536-a13fdc0767f6', 'MT.1.NS.OS.3', 'Use several devices to demonstrate relationships among the number facts for addition and subtraction (e.g., if 5 + 4 = 9 then 9 – 5 = 4) and to complete addition and subtraction statements by filling in a missing value in any position (e.g. 8 - __ = 6 and __+ 2 = 5).', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('92608b10-e338-4c61-a848-84ff2f507fc3', 'MT.1.NS.OS.4', 'Add up to three one-digit numbers with totals up to 20, using objects and pictures/diagrams.', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('3370789a-27f7-46ae-a1d3-7d452d4ef66e', 'MT.1.NS.OS.5', 'Mentally add two one-digit numbers with totals up to 18.', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('87cedd3d-c716-4d6e-b2ba-246fce1a4a55', 'MT.1.NS.OS.6', 'Subtract a one-digit number from numbers up to 20, with the aid of concrete objects, pictorial representations and diagrams.', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e3f6db76-647c-4d0d-b4d0-eeb41e5e2ac9', 'MT.1.NS.OS.7', 'Write number sentences to represent situations involving the addition or subtraction of two quantities.', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e81e891d-e556-48be-8f21-070984f4b50b', 'MT.1.NS.OS.8', 'Describe repeated addition situations with totals up to 12; and using the terms ''sets of'', ''groups of'' to describe repeated addition procedures.', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('67567579-a436-4638-83c5-398f7fa71a5a', 'MT.1.NS.OS.9', 'Use objects, pictures/diagrams and number statements to show situations involving repeated addition (e.g., 2 +2 +2 = 6 and 3 sets of 2 make 6).', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('88e74a31-d0ee-47d0-8cbc-f10b9ecd9f87', 'MT.1.NS.OS.10', 'Use the calculation to perform one digit addition and subtraction problems with products up to 12 using the repeated addition concept.', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('31d5825a-9458-4d36-8fcf-3f8028dc8792', 'MT.1.NS.OS.11', 'Create and solve problems involving addition, subtraction and repeated addition', 'mathematics', '1', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f696dc95-6e9a-453e-abbb-3bdbb6ea59e8', 'MT.1.NS.PR.1', 'Identify a whole and parts of a whole.', 'mathematics', '1', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f9896723-2a5e-4b0b-896d-a30976c91a04', 'MT.1.NS.PR.2', 'Identify and represent one-half and one-quarter of a whole, using different models (such area, linear, volume)', 'mathematics', '1', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7840be38-fb28-4ac0-9e65-8605429cd59b', 'MT.1.NS.PR.3', 'Read and write the fractions ½ and ¼ correctly as ''one half'' and ''one quarter'' (NOT ''one over two'' and ''one over four'').', 'mathematics', '1', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e763718e-5704-40c5-9cfe-9441b7e46510', 'MT.1.NS.UN.1', 'Count in a variety of ways (by 1''s and 10''s to 100; by 2''s and 5''s to 50; backwards from 10; and count on, in 1''s from a given number up to 100)', 'mathematics', '1', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d1d86a6f-ac4d-4cd5-82eb-a455d781f2a5', 'MT.1.NS.UN.2', 'Represent numbers up to twenty in a variety of ways (in words, in numbers, using counting blocks/rods; drawings/pictures, etc.)', 'mathematics', '1', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('894ea6c1-71f2-4cae-8050-cfcca50ca565', 'MT.1.NS.UN.3', 'Count and identify the number of objects in a set of up to 20 objects; and make and draw sets of up to 20 objects.', 'mathematics', '1', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('14eb3597-c404-4fa5-9c6c-521ed8091547', 'MT.1.NS.UN.4', 'Make and draw a set that is equal to, one more than, or one less than a given set.', 'mathematics', '1', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0b8e0637-2b27-4d47-9b76-23241d65e4f9', 'MT.1.NS.UN.5', 'Compare sets of objects and pairs of numbers up to twenty using phrases (such as: ''less than'', ''same as'', ''greater than'')', 'mathematics', '1', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b8c1b9e5-ae2d-40fa-8cb7-b0f5af1e573c', 'MT.1.NS.UN.6', 'Read and write numbers up to 20.', 'mathematics', '1', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('38436bc9-93c7-46c5-bf06-4f6b0abd687b', 'MT.1.NS.UN.7', 'Identify the position of an object in an ordinal arrangement of up to 10 objects.', 'mathematics', '1', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('02260648-473e-4d2a-9ce1-0c56463b07da', 'MT.1.NS.UN.8', 'Use collective number names such as pair, set, group.', 'mathematics', '1', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('831ffba9-f2a3-4d15-ada3-f103be04176a', 'MT.1.NS.UN.9', 'Demonstrate fluency when working with whole numbers up to 20 (e.g. speak of 12 as: ten plus two; six plus six; one less than thirteen, etc.)', 'mathematics', '1', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', '', 'K-2', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('89a7b351-f1c3-4343-818c-0311d013de93', 'MT.2.DH.DC.1', 'Ask questions which can be used to collect data', 'mathematics', '2', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cbc73f75-bd4d-4ba5-b54e-dfff195f28a2', 'MT.2.DH.DC.2', 'Collect simple sets of data through observation and simple interviews.', 'mathematics', '2', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('57a31b8c-4f88-4d86-97cc-a72e3fd6e4c4', 'MT.2.DH.DC.3', 'Record collected data accurately in a variety of ways', 'mathematics', '2', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('725826a2-8b4b-4ee5-94d8-fd6850049843', 'MT.2.DH.DI.1', 'Read and interpret data presented in simple tables, pictographs and bar charts', 'mathematics', '2', 'Data Handling', 'DH', 'Data Interpretation', 'DI', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('71b0e5e8-4b9e-4914-acb1-9c55471009ed', 'MT.2.DH.DI.2', 'Ask and answer questions based on data presented in simple tables, bar charts, pictograph', 'mathematics', '2', 'Data Handling', 'DH', 'Data Interpretation', 'DI', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('aec3e3e8-9e1d-492b-8fe3-cafe5ea7cab2', 'MT.2.DH.DR.1', 'Represent recorded data by filling in templates for pictographs with available picture cards, where one picture represents one unit of data.', 'mathematics', '2', 'Data Handling', 'DH', 'Data Representation', 'DR', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('74c2f78b-929c-445e-933c-23fb9cfe656e', 'MT.2.DH.DR.2', 'Construct bar charts to represent data, using rectangular bars where one bar represents one unit in the data set', 'mathematics', '2', 'Data Handling', 'DH', 'Data Representation', 'DR', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('48a1f80e-b47e-45b4-b481-0da3e32e68c5', 'MT.2.GT.DS.1', 'Identify the relative position of objects or people presented in concrete and pictorial form, using positional language (such as above, below, in front of, beside and between, to the right of, to the left of )', 'mathematics', '2', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('bf31270f-0648-44da-87ee-305274764f64', 'MT.2.GT.DS.2', 'Follow and give simple instructions involving directions (such as move two steps forward; move three steps backward, move two strides to the right, etc.)', 'mathematics', '2', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('2455da0f-3dbd-4636-ad51-fdf6c81ed37d', 'MT.2.GT.DS.3', 'Begin to use vocabulary which indicate opposite positions (such as ''top side'' and ''bottom side'', ''right side'' and ''left side'') when describing the rectangle', 'mathematics', '2', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a3dcc70d-fe3e-4872-9055-7bfb247a846b', 'MT.2.GT.PL.1', 'Distinguish between curves and straight lines.', 'mathematics', '2', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8eebe521-0777-4b1e-a93f-8e21a8eda35f', 'MT.2.GT.PL.2', 'Classify curves as being closed or open', 'mathematics', '2', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('6b661bf3-e2fe-4640-aecc-e0550a1d490b', 'MT.2.GT.PL.3', 'Use a straight edge (e.g. ruler) to draw straight lines in different orientations', 'mathematics', '2', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a6d76234-4d51-4891-a38a-8409a9754b68', 'MT.2.GT.PS.1', 'Identify, describe and classify plane shapes (squares, rectangles, triangles, and circles) based on the number, length and shape of their sides (on concrete objects, in diagrams, and in pictures).', 'mathematics', '2', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
