  ('e6401cbc-5ffb-4221-b63b-448e10c772f3', 'MT.2.NS.OS.1', 'Recall the basic facts for addition and subtraction.', 'mathematics', '2', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7851e48e-2717-42ec-9790-27ce7a0aa2f9', 'MT.2.NS.OS.2', 'Use a variety of strategies and tools to add sets of two numbers (one and two-digit) without and with regrouping with totals up to 99; and explain strategies used.', 'mathematics', '2', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
