  ('4ae56955-b4ca-4005-9a9f-4512895ff943', 'MT.2.NS.OS.7', 'Use a variety of strategies (such as concrete objects, a number line, or numerals) to illustrate division as repeated subtraction.', 'mathematics', '2', 'Number Sense', 'NS', 'Operational Sense', 'OS', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
